    "content": "import React from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Float, Sphere } from '@react-three/drei';
import './App.css';

function FloatingSphere() {
  return (
    <Float speed={2} rotationIntensity={1} floatIntensity={2}>
      <Sphere args={[1, 100, 200]} scale={2}>
        <meshStandardMaterial
          color="#4f46e5"
          wireframe={false}
          roughness={0.1}
          metalness={0.9}
        />
      </Sphere>
    </Float>
  );
}

function Scene() {
  return (
    <Canvas className="w-full h-screen">
      <ambientLight intensity={0.5} />
      <pointLight position={[10, 10, 10]} intensity={1.5} />
      <FloatingSphere />
      <OrbitControls enableZoom={false} autoRotate autoRotateSpeed={2} />
    </Canvas>
  );
}

function App() {
  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-900 to-black text-white relative overflow-hidden">
      {/* Glassmorphism Navigation */}
      <nav className="fixed top-0 left-0 w-full z-50 p-6">
        <div className="glass-container mx-auto max-w-7xl flex justify-between items-center">
          <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-500 to-purple-500">
            Louis Portfolio
          </h1>
          <div className="space-x-6">
            <a href="#" className="hover:text-indigo-400 transition-colors">Home</a>
            <a href="#" className="hover:text-indigo-400 transition-colors">Projects</a>
            <a href="#" className="hover:text-indigo-400 transition-colors">Contact</a>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="relative z-10 pt-32 pb-20 px-6">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
          {/* Text Content */}
          <div className="space-y-8">
            <h1 className="text-5xl md:text-7xl font-extrabold tracking-tight">
              <span className="block">Interactive</span>
              <span className="block bg-clip-text text-transparent bg-gradient-to-r from-indigo-500 to-purple-500">3D Portfolio</span>
            </h1>
            <p className="text-xl text-gray-300 max-w-2xl">
              A modern portfolio website featuring stunning 3D visuals, glassmorphism design, and seamless user experience.
            </p>
            <div className="flex flex-wrap gap-4">
              <button className="px-8 py-4 bg-indigo-600 hover:bg-indigo-700 rounded-lg font-semibold transition-all transform hover:scale-105">
                View Projects
              </button>
              <button className="px-8 py-4 bg-transparent border-2 border-indigo-600 text-indigo-400 hover:bg-indigo-600/10 rounded-lg font-semibold transition-all">
                Contact Me
              </button>
            </div>
          </div>

          {/* 3D Scene */}
          <div className="h-96 md:h-[500px] rounded-3xl overflow-hidden shadow-2xl">
            <Scene />
          </div>
        </div>
      </main>

      {/* Glassmorphism Footer */}
      <footer className="relative z-10 py-10 text-center text-gray-500 border-t border-gray-800/50">
        <div className="max-w-7xl mx-auto px-6">
          <p>© {new Date().getFullYear()} Louis Portfolio. All rights reserved.</p>
        </div>
      </footer>
    </div>
  );
}

export default App;"
  }
}

